    auto& graph = reaction::ObserverGraph::instance();
    reaction::NodeId sensor1 = graph.createNode();
    reaction::NodeId sensor2 = graph.createNode();

    // 3. Register nodes
    auto observerId = graph.registerObserver(&observer);

    // 4. Set up initial dependency (observer depends on sensor1)
    graph.addDependency(sensor1, observerId);

    // 5. Save node state for rollback
    auto transaction = graph.beginTransaction();

    // 6. Replace dependencies transactionally:
    //    remove dependency on sensor1, add dependency on sensor2
    graph.removeDependency(sensor1, observerId, transaction);
    graph.addDependency(sensor2, observerId, transaction);

