    reaction::NodeId sensor1 = graph.createNode();
    reaction::NodeId sensor2 = graph.createNode();

    // 3. Register nodes
    auto observerId = graph.registerObserver(&observer);

    // 4. Set up initial dependency (observer depends on sensor1)
    graph.addDependency(sensor1, observerId);

    // 5. Save node state for rollback
    auto transaction = graph.beginTransaction();

    // 6. Replace dependencies transactionally:
    //    remove dependency on sensor1, add dependency on sensor2
    graph.removeDependency(sensor1, observerId, transaction);
    graph.addDependency(sensor2, observerId, transaction);

    // 7. Trigger notification on second sensor
    graph.notifyValueChanged(sensor2, true);

    // 8. Record notification count after second binding
    int notificationsAfterSecondBinding = observer.notificationCount();

    // 9. Execute rollback (revert to dependency on sensor1)
    graph.rollbackTransaction(transaction);

    // 10. Trigger notification on first sensor
    graph.notifyValueChanged(sensor1, true);

    // 11. Record notification count after rollback
    int notificationsAfterRollback = observer.notificationCount();

    // 12. Return notification counts
    return RollbackObservation{
        notificationsAfterSecondBinding,
        notificationsAfterRollback,
    };
}

}  // namespace test_reaction

