    batchObject.close();
    const bool closedAfterClose = batchObject.isClosed();

    (void)doubled.get();

    return BatchLifecycleResult{
        .closedInitially = closedInitially,
        .closedAfterClose = closedAfterClose,
        .recomputeCountAfterExecute = recomputeAfterExecute,
    };
}

