#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

class CacheProbeNode : public reaction::ObserverNode {
public:
    void valueChanged(bool changed = true) override {
        // For the purposes of this test, we don't need any special behavior here.
        reaction::ObserverNode::valueChanged(changed);
    }
};

struct CacheStatsSnapshot {
    size_t graphEntriesBeforeCleanup;
    size_t graphEntriesAfterCleanup;
    double graphHitRatioAfterCleanup;
};

inline CacheStatsSnapshot test_observer_cache_stats() {
    using namespace reaction;

    // 1. Create CacheProbeNode instances
    auto* root = new CacheProbeNode();
    auto* child1 = new CacheProbeNode();
    auto* child2 = new CacheProbeNode();
    auto* grandChild = new CacheProbeNode();

    // 2. Get observer graph instance
    auto& graph = ObserverGraph::instance();

    // 3. Register nodes
    graph.registerNode(root);
    graph.registerNode(child1);
    graph.registerNode(child2);
    graph.registerNode(grandChild);

    // 4. Set up direct observer relationship
    // root observes child1 and child2 directly
    graph.addObserver(child1, root);
    graph.addObserver(child2, root);

    // 5. Set up transitive observer relationship
    // grandChild is observed by child1, so root transitively observes grandChild
    graph.addObserver(grandChild, child1);

    // 6. Create NodeSet to store collected observers
    NodeSet collected;

    // 7. Populate cache data
    // Access observers several times to make sure cache is populated
    for (int i = 0; i < 5; ++i) {
        collected.clear();
        graph.collectObservers(grandChild, collected);  // transitively should include child1 and root
        collected.clear();
        graph.collectObservers(child1, collected);      // should include root
        collected.clear();
        graph.collectObservers(child2, collected);      // should include root
    }

    // 8. Get cache statistics before cleanup
    auto statsBefore = graph.cacheStats();
    CacheStatsSnapshot snapshot{};
    snapshot.graphEntriesBeforeCleanup = statsBefore.size;

    // 9. Trigger cache cleanup
    graph.cleanupCache();

    // 10. Get cache statistics after cleanup
    auto statsAfter = graph.cacheStats();
    snapshot.graphEntriesAfterCleanup = statsAfter.size;
    snapshot.graphHitRatioAfterCleanup =
        statsAfter.lookups ? (static_cast<double>(statsAfter.hits) /
                              static_cast<double>(statsAfter.lookups))
                           : 0.0;

    // 11. Close all nodes
    graph.unregisterNode(root);
    graph.unregisterNode(child1);
    graph.unregisterNode(child2);
    graph.unregisterNode(grandChild);

    delete root;
    delete child1;
    delete child2;
    delete grandChild;

    // 12. Return cache stats snapshot
    return snapshot;
}

}  // namespace test_reaction
