#pragma once

#include <array>
#include <cstddef>
#include <reaction/memory/sbo_resource.h>
#include <reaction/value.h>

namespace test_reaction {

struct SmallPayload {
    int value;
    bool operator!=(const SmallPayload& other) const = default;
};

struct LargePayload {
    std::array<int, 64> data{};
    bool operator!=(const LargePayload& other) const = default;
};

struct SboStorageStatus {
    bool updateReportedChange;
    bool smallUsingSBO;
    std::size_t smallStackUsage;
    bool largeInitialized;
    bool largeUsingSBO;
};

inline SboStorageStatus test_sbo_storage_info(int initialSmall,
                                              int updatedSmall,
                                              int largeSeed) {
    using reaction::memory::sbo_resource;
    using reaction::value;

    // 1. Lambda to create a large payload from a seed
    auto makeLargePayload = [](int seed) {
        LargePayload lp;
        for (std::size_t i = 0; i < lp.data.size(); ++i) {
            lp.data[i] = seed + static_cast<int>(i);
        }
        return lp;
    };

    // 2. Create small SBOResource
    sbo_resource<SmallPayload> smallResource{SmallPayload{initialSmall}};
    value<SmallPayload> smallVal{smallResource};

    // 3. Create large SBOResource
    sbo_resource<LargePayload> largeResource{};
    value<LargePayload> largeVal{largeResource};
    bool largeInitialized = false;
    bool largeUsingSBO   = false;

    // Initialize large resource via value abstraction
    largeVal.write(makeLargePayload(largeSeed));
    largeInitialized = true;
    largeUsingSBO = largeResource.using_sbo();

    // 4. Update small resource value
    bool updateReportedChange = smallVal.write(SmallPayload{updatedSmall});

    // 5. Get storage information for small resource
    bool smallUsingSBO    = smallResource.using_sbo();
    std::size_t smallStackUsage = smallResource.stack_bytes_used();

    // 6. Storage info for large resource already captured:
    //    - largeUsingSBO
    //    - largeInitialized

    // 7. Return SBO storage status
    return SboStorageStatus{
        updateReportedChange,
        smallUsingSBO,
        smallStackUsage,
        largeInitialized,
        largeUsingSBO};
}

}  // namespace test_reaction
