/*
 * This implementation assumes the following (typical) API in the `reaction` library:
 *
 * - reaction::ThreadManager::instance()
 * - void reaction::ThreadManager::reset()
 * - bool reaction::ThreadManager::enableThreadSafety(bool enabled)
 * - bool reaction::ThreadManager::isThreadSafetyEnabled() const
 *
 * - template<typename T> auto reaction::make_var(const T& initial)
 *     -> some reactive variable type with:
 *       - void set(const T&)
 *       - T get() const
 *
 * - template<typename F> auto reaction::make_calc(F&& f)
 *     -> some reactive calculation type with:
 *       - auto value() const  (or get())
 *       - void reset_logic()
 *
 * If your actual API differs, adjust the names/signatures accordingly.
 */
ResetBehaviorSnapshot test_react_reset_behavior(int initialValue, int multiplier) {
    // 1. Get thread manager instance
    auto& tm = reaction::ThreadManager::instance();

    // 2. Reset thread manager state
    tm.reset();

    // 3. Create a reactive variable
    auto source = reaction::make_var(initialValue);

    // 4. Create a calculation: value = source * multiplier
    auto calc = reaction::make_calc([&]() {
        return source.get() * multiplier;
    });

