        // will either succeed (guardHeld = true) or fail (guardHeld = false)
        // if limits are exceeded.
        constexpr std::size_t kLargeGuardSize = 1 << 20;  // 1 MiB as an example

        StackMonitor::StackGuard guard(kLargeGuardSize);
        snapshot.guardHeld = guard.is_held();

