        } else {
            snapshot.allocationBlockedWhileGuardHeld = false;
        }

        // Guard goes out of scope here, releasing any reserved stack quota.
    }

    // 9. Get usage statistics after guard
    snapshot.statsAfterGuard = StackMonitor::get_usage_stats();

